// Solution
function validatePortMappings(portMappings) {
    let valid = true;
    let hostPorts = new Set();
    for (let i = 0; i < portMappings.length; i++) {
        let containerPort = portMappings[i][0];
        let hostPort = portMappings[i][1];
        if (containerPort > hostPort) {
            valid = false;
            break;
        }
        if (hostPort < 1 || hostPort > 65535) {
            valid = false;
            break;
        }
        if (hostPorts.has(hostPort)) {
            valid = false;
            break;
        }
        hostPorts.add(hostPort);
    }
    return valid;
}

