class Solution:
    def validatePortMappings(self, portMappings):
        valid = True
        hostPorts = set()
        for containerPort, hostPort in portMappings:
            if containerPort > hostPort:
                valid = False
                break
            if hostPort < 1 or hostPort > 65535:
                valid = False
                break
            if hostPort in hostPorts:
                valid = False
                break
            hostPorts.add(hostPort)
        return valid;
